prompt --application/shared_components/security/authentications/dann_alpes_auth
begin
wwv_flow_imp_shared.create_authentication(
 p_id=>wwv_flow_imp.id(3493530614363319977)
,p_name=>'Dann Alpes Auth'
,p_static_id=>'dann-alpes-auth'
,p_scheme_type=>'NATIVE_CUSTOM'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'authentication_function', 'DANN_AUTH',
  'enable_legacy_attributes', 'N')).to_clob
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'FUNCTION DANN_AUTH(p_username IN VARCHAR2, p_password IN VARCHAR2) RETURN BOOLEAN',
'IS',
'  l_count NUMBER;',
'BEGIN',
'  SELECT COUNT(*) INTO l_count',
'  FROM ADMINISTRADORES_DANN',
'  WHERE EMAIL_ADMIN = UPPER(p_username)',
'  AND CONTRASENA_ADMIN = p_password;',
'  ',
'  IF l_count > 0 THEN',
'    RETURN TRUE;',
'  END IF;',
'  ',
'  SELECT COUNT(*) INTO l_count',
'  FROM CLIENTES_DANN',
'  WHERE EMAIL = LOWER(p_username)',
'  AND CONTRASENA = p_password;',
'  ',
'  IF l_count > 0 THEN',
'    RETURN TRUE;',
'  END IF;',
'  ',
'  RETURN FALSE;',
'END DANN_AUTH;'))
,p_invalid_session_type=>'LOGIN'
,p_use_secure_cookie_yn=>'N'
,p_ras_mode=>0
,p_version_scn=>'SH256:1nZ096Y27d4LCllV6DyYHo7jMpQKg37Aaxh81nD1NTw'
