,p_title=>unistr('Rese\00F1a Hotel')
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>4073835273271169698
,p_plug_display_sequence=>30
,p_plug_item_display_point=>'ABOVE'
,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_url        VARCHAR2(500);',
'  l_response   CLOB;',
'  l_json       APEX_JSON.t_values;',
'  l_count      NUMBER;',
'  l_resena_id  VARCHAR2(100);',
'  l_es_admin   NUMBER := 0;',
'BEGIN',
'  SELECT COUNT(*) INTO l_es_admin',
'  FROM ADMINISTRADORES_DANN',
'  WHERE EMAIL_ADMIN = :APP_USER;',
'',
'  l_url := ''https://s1-g8-2026-1.onrender.com/hoteles/'' || :P2_ID_HOTEL || ''/resenas'';',
'  l_response := APEX_WEB_SERVICE.MAKE_REST_REQUEST(',
'    p_url         => l_url,',
'    p_http_method => ''GET''',
'  );',
'  ',
'  APEX_JSON.parse(l_json, l_response);',
'  l_count := APEX_JSON.get_count(p_values => l_json, p_path => ''resenas'');',
'  ',
'  HTP.P(''<div style="font-family:Arial;">'');',
'  ',
'  IF l_count = 0 OR l_count IS NULL THEN',
unistr('    HTP.P(''<p>No hay rese\00F1as disponibles para este hotel. \00A1S\00E9 el primero en opinar!</p>'');'),
'  ELSE',
'    FOR i IN 1..l_count LOOP',
'      l_resena_id := APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''resenas[%d].resenaId'', p0=>i);',
'      HTP.P(''<div style="border:1px solid #ddd; border-radius:8px; padding:15px; margin-bottom:15px;">'');',
'      HTP.P(''<h4>'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''resenas[%d].asunto'', p0=>i) || ''</h4>'');',
'      HTP.P(''<p>'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''resenas[%d].resenaRespecitva'', p0=>i) || ''</p>'');',
'      HTP.P(''<p><b>Nota:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''resenas[%d].nota'', p0=>i) || ''/5</p>'');',
'      HTP.P(''<p><b>Fecha:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''resenas[%d].fechaDeCreacion'', p0=>i) || ''</p>'');',
unistr('      HTP.P(''<p><b>\00DAtil para:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''resenas[%d].utilidad'', p0=>i) || '' personas</p>'');'),
'      HTP.P(''<button onclick="fetch(''''https://s1-g8-2026-1.onrender.com/hoteles/'' || :P2_ID_HOTEL || ''/resenas/'' || l_resena_id || ''/util'''', {method:''''POST'''', headers:{''''Content-Type'''':''''application/json''''}, body: JSON.stringify({clienteId:'''''' || :AP'
||unistr('P_USER || ''''''})}).then(r=>r.json()).then(d=>location.reload());" style="padding:5px 10px; background:#28a745; color:white; border-radius:4px; border:none; cursor:pointer; margin-right:5px;">\D83D\DC4D \00DAtil</button>'');'),
'      IF l_es_admin > 0 THEN',
'        HTP.P(''<a href="f?p='' || :APP_ID || '':9:'' || :APP_SESSION || ''::NO::P9_RESPONDER_RESENA_ID,P9_ID_HOTEL:'' || l_resena_id || '','' || :P2_ID_HOTEL || ''" style="padding:5px 10px; background:#6c757d; color:white; border-radius:4px; text-decoration:'
||unistr('none;">\2699 Administrar</a>'');'),
'      END IF;',
'      HTP.P(''</div>'');',
'    END LOOP;',
'  END IF;',
'  ',
'  HTP.P(''</div>'');',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
,p_ajax_items_to_submit=>'P2_ID_HOTEL'
,p_created_on=>wwv_flow_imp.dz('20260524133322Z')
,p_updated_on=>wwv_flow_imp.dz('20260524235308Z')
,p_created_by=>'I.BARBOSAC@UNIANDES.EDU.CO'
,p_updated_by=>'I.BARBOSAC@UNIANDES.EDU.CO'
);
