wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(3412745682740239326)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>unistr('Crear Rese\00F1a API')
,p_static_id=>unistr('crear-rese\00F1a-api')
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_url        VARCHAR2(500);',
'  l_body       CLOB;',
'  l_response   CLOB;',
'  l_reserva_id VARCHAR2(100);',
'  l_nombre_hotel VARCHAR2(200);',
'  l_ciudad       VARCHAR2(100);',
'BEGIN',
'  l_reserva_id := ''RES_'' || :APP_USER || ''_'' || TO_CHAR(SYSDATE, ''YYYYMMDDHH24MISS'');',
'',
'  -- Obtener nombre y ciudad del hotel desde Oracle',
'  SELECT NOMBRE, CIUDAD INTO l_nombre_hotel, l_ciudad',
'  FROM BARES',
'  WHERE ID = :P2_ID_HOTEL;',
'',
'  l_url := ''https://s1-g8-2026-1.onrender.com/hoteles/'' || :P2_ID_HOTEL || ''/resenas'';',
'  ',
'  l_body := ''{"clienteId":"'' || :APP_USER || ''",'' ||',
'            ''"reservaId":"'' || l_reserva_id || ''",'' ||',
'            ''"asunto":"'' || :P2_ASUNTO || ''",'' ||',
'            ''"resenaRespecitva":"'' || :P2_RESENA || ''",'' ||',
'            ''"nota":'' || :P2_NOTA || '','' ||',
'            ''"nombreHotel":"'' || l_nombre_hotel || ''",'' ||',
'            ''"ciudad":"'' || l_ciudad || ''",'' ||',
'            ''"usuarioPublico":{"nombre":"'' || :APP_USER || ''","email":"'' || :APP_USER || ''"}}'';',
'',
'  APEX_WEB_SERVICE.SET_REQUEST_HEADERS(',
'    p_name_01  => ''Content-Type'',',
'    p_value_01 => ''application/json''',
'  );',
'  l_response := APEX_WEB_SERVICE.MAKE_REST_REQUEST(',
'    p_url         => l_url,',
'    p_http_method => ''POST'',',
'    p_body        => l_body',
'  );',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(3412746176634239331)
,p_internal_uid=>3412745682740239326
,p_created_on=>wwv_flow_imp.dz('20260524134233Z')
,p_updated_on=>wwv_flow_imp.dz('20260525000708Z')
