,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_url        VARCHAR2(500);',
'  l_response   CLOB;',
'  l_json       APEX_JSON.t_values;',
'  l_count      NUMBER;',
'  l_resena_id  VARCHAR2(100);',
'  l_hotel_id   VARCHAR2(20);',
'BEGIN',
'  l_url := ''https://s1-g8-2026-1.onrender.com/clientes/'' || :APP_USER || ''/resenas'';',
'  l_response := APEX_WEB_SERVICE.MAKE_REST_REQUEST(',
'    p_url         => l_url,',
'    p_http_method => ''GET''',
'  );',
'  ',
'  APEX_JSON.parse(l_json, l_response);',
'  l_count := APEX_JSON.get_count(p_values => l_json, p_path => ''.'');',
'  ',
'  HTP.P(''<div style="font-family:Arial;">'');',
'  ',
'  IF l_count = 0 OR l_count IS NULL THEN',
unistr('    HTP.P(''<p>No tienes rese\00F1as todav\00EDa.</p>'');'),
'  ELSE',
'    FOR i IN 1..l_count LOOP',
'      l_resena_id := APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].resenaId'', p0=>i);',
'      l_hotel_id  := APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].idHotel'', p0=>i);',
'      HTP.P(''<div style="border:1px solid #ddd; border-radius:8px; padding:15px; margin-bottom:15px;">'');',
'      HTP.P(''<h4>'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].asunto'', p0=>i) || ''</h4>'');',
'      HTP.P(''<p><b>Hotel:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].hotel'', p0=>i) || ''</p>'');',
'      HTP.P(''<p><b>Nota:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].nota'', p0=>i) || ''/5</p>'');',
'      HTP.P(''<p><b>Fecha:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].fechaDeCreacion'', p0=>i) || ''</p>'');',
'      HTP.P(''<p><b>Estado:</b> '' || CASE WHEN APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].publico'', p0=>i) = ''true'' THEN ''Publicada'' ELSE ''No publicada'' END || ''</p>'');',
unistr('      HTP.P(''<p><b>\00DAtil para:</b> '' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].utilidad'', p0=>i) || '' personas</p>'');'),
unistr('      HTP.P(''<p><b>Tiene respuesta:</b> '' || CASE WHEN APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''[%d].tieneRespuesta'', p0=>i) = ''true'' THEN ''S\00ED'' ELSE ''No'' END || ''</p>'');'),
'      HTP.P(''<a href="f?p='' || :APP_ID || '':8:'' || :APP_SESSION || ''::NO::P8_EDITAR_RESENA_ID,P8_ID_HOTEL:'' || l_resena_id || '','' || l_hotel_id || ''" style="padding:5px 10px; background:#0070c0; color:white; border-radius:4px; text-decoration:none; m'
||'argin-right:5px;">Editar</a>'');',
'      HTP.P(''<button onclick="fetch(''''https://s1-g8-2026-1.onrender.com/hoteles/'' || l_hotel_id || ''/resenas/'' || l_resena_id || ''?clienteId='' || :APP_USER || '''''', {method:''''DELETE''''}).then(r=>r.json()).then(d=>location.reload());" style="padding:5px'
||' 10px; background:#c00; color:white; border-radius:4px; border:none; cursor:pointer;">Eliminar</button>'');',
'      HTP.P(''</div>'');',
'    END LOOP;',
'  END IF;',
'  ',
'  HTP.P(''</div>'');',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
,p_created_on=>wwv_flow_imp.dz('20260524155008Z')
,p_updated_on=>wwv_flow_imp.dz('20260524235653Z')
,p_created_by=>'I.BARBOSAC@UNIANDES.EDU.CO'
,p_updated_by=>'I.BARBOSAC@UNIANDES.EDU.CO'
);
