,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_url      VARCHAR2(500);',
'  l_response CLOB;',
'  l_json     APEX_JSON.t_values;',
'  l_count    NUMBER;',
'  l_ciudad   VARCHAR2(100);',
'  l_promedio VARCHAR2(20);',
'BEGIN',
'  l_ciudad := NVL(:P6_CIUDAD, ''Cartagena'');',
'',
'  l_url := ''https://s1-g8-2026-1.onrender.com/consultas/comparativo?ciudad='' || l_ciudad;',
'',
'  l_response := APEX_WEB_SERVICE.MAKE_REST_REQUEST(',
'    p_url         => l_url,',
'    p_http_method => ''GET''',
'  );',
'',
'  APEX_JSON.parse(l_json, l_response);',
'  l_promedio := APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''promedioDeciudad'');',
'  l_count    := APEX_JSON.get_count(p_values=>l_json, p_path=>''hoteles'');',
'',
'  HTP.P(''<p><b>Promedio de la ciudad:</b> '' || l_promedio || ''/5</p>'');',
'  HTP.P(''<table style="width:100%; border-collapse:collapse;">'');',
'  HTP.P(''<tr style="background:#f0f0f0;">',
'    <th style="padding:10px; border:1px solid #ddd;">Hotel</th>',
unistr('    <th style="padding:10px; border:1px solid #ddd;">Calificaci\00F3n</th>'),
