'    <th style="padding:10px; border:1px solid #ddd;">% Con Respuesta</th>',
'    <th style="padding:10px; border:1px solid #ddd;">% Destacadas</th>',
'    <th style="padding:10px; border:1px solid #ddd;">Bajo Promedio</th>',
'  </tr>'');',
'',
'  FOR i IN 1..l_count LOOP',
'    HTP.P(''<tr>'');',
'    HTP.P(''<td style="padding:10px; border:1px solid #ddd;">'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''hoteles[%d].nombreHotel'', p0=>i) || ''</td>'');',
'    HTP.P(''<td style="padding:10px; border:1px solid #ddd;">'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''hoteles[%d].calificacionPromedio'', p0=>i) || ''/5</td>'');',
'    HTP.P(''<td style="padding:10px; border:1px solid #ddd;">'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''hoteles[%d].totalResenas'', p0=>i) || ''</td>'');',
