'    HTP.P(''<td style="padding:10px; border:1px solid #ddd;">'' || APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''hoteles[%d].porcentajeDestacadas'', p0=>i) || ''%</td>'');',
unistr('    HTP.P(''<td style="padding:10px; border:1px solid #ddd;">'' || CASE WHEN APEX_JSON.get_varchar2(p_values=>l_json, p_path=>''hoteles[%d].bajoPromedio'', p0=>i) = ''true'' THEN ''\26A0 S\00ED'' ELSE ''No'' END || ''</td>'');'),
'    HTP.P(''</tr>'');',
'  END LOOP;',
'  HTP.P(''</table>'');',
'END;'))
