'-- BTN_ADMIN_ELIMINAR',
'DECLARE',
'  l_url      VARCHAR2(500);',
'  l_response CLOB;',
'  l_admin_id VARCHAR2(20);',
'BEGIN',
'  SELECT ID_ADMIN INTO l_admin_id',
'  FROM ADMINISTRADORES_DANN',
'  WHERE EMAIL_ADMIN = :APP_USER;',
