'-- BTN_RESPONDER',
'DECLARE',
'  l_url        VARCHAR2(500);',
'  l_body       CLOB;',
'  l_response   CLOB;',
'  l_admin_id   VARCHAR2(20);',
'  l_admin_nombre VARCHAR2(100);',
'BEGIN',
'  SELECT ID_ADMIN, NOMBRE_ADMIN INTO l_admin_id, l_admin_nombre',
'  FROM ADMINISTRADORES_DANN',
'  WHERE EMAIL_ADMIN = :APP_USER;',
'',
'  l_url := ''https://s1-g8-2026-1.onrender.com/hoteles/'' || :P9_ID_HOTEL || ',
'           ''/resenas/'' || :P9_RESPONDER_RESENA_ID || ''/respuesta'';',
'  l_body := ''{"adminId":"'' || l_admin_id || ''",'' ||',
'            ''"administrador":"'' || l_admin_nombre || ''",'' ||',
'            ''"respuesta":"'' || :P9_RESPUESTA || ''"}'';',
'  APEX_WEB_SERVICE.SET_REQUEST_HEADERS(p_name_01=>''Content-Type'', p_value_01=>''application/json'');',
'  l_response := APEX_WEB_SERVICE.MAKE_REST_REQUEST(p_url=>l_url, p_http_method=>''POST'', p_body=>l_body);',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
